import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatButtonModule } from '@angular/material/button';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    RouterLink,
    MatCardModule,
    MatFormFieldModule,
    MatInputModule,
    MatButtonModule,
    MatProgressSpinnerModule,
  ],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss',
})
export class LoginComponent {
  form: FormGroup;
  loading = false;
  errorMessage = '';

  constructor(
    private fb: FormBuilder,
    private router: Router,
    private authService: AuthService
  ) {
    this.form = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.minLength(4)]],
    });
    if (this.authService.isLoggedIn()) {
      this.router.navigate(['/main']);
    }
  }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.loading = true;
    this.errorMessage = '';
    this.authService.login(this.form.value.email, this.form.value.password).subscribe({
      next: (user) => {
        this.loading = false;
        this.router.navigate(['/main']);
      },
      error: (err) => {
        this.loading = false;
        this.errorMessage =
          err?.error?.message ??
          'Error al conectar con el servidor. Verifica que la API esté en ejecución.';
      },
    });
  }
}
<div class="login-page">
  <mat-card class="login-card">
    <mat-card-header>
      <mat-card-title>ProBook</mat-card-title>
      <mat-card-subtitle>Hospedaje digital, experiencias personalizadas</mat-card-subtitle>
    </mat-card-header>
    <mat-card-content>
      <form [formGroup]="form" (ngSubmit)="onSubmit()">
        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Correo electrónico</mat-label>
          <input matInput type="email" formControlName="email" placeholder="usuario@ejemplo.com">
          <mat-error *ngIf="form.get('email')?.hasError('required')">El correo es obligatorio</mat-error>
          <mat-error *ngIf="form.get('email')?.hasError('email')">Correo no válido</mat-error>
        </mat-form-field>
        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Contraseña</mat-label>
          <input matInput type="password" formControlName="password" placeholder="••••••••">
          <mat-error *ngIf="form.get('password')?.hasError('required')">La contraseña es obligatoria</mat-error>
          <mat-error *ngIf="form.get('password')?.hasError('minlength')">Mínimo 4 caracteres</mat-error>
        </mat-form-field>
        <p class="error-msg" *ngIf="errorMessage">{{ errorMessage }}</p>
        <button mat-flat-button color="primary" type="submit" class="full-width submit-btn" [disabled]="loading">
          <mat-spinner *ngIf="loading" diameter="24" class="btn-spinner"></mat-spinner>
          <span *ngIf="!loading">Iniciar sesión</span>
        </button>
      </form>
    </mat-card-content>
    <mat-card-actions class="card-footer">
      <a routerLink="/register" class="register-link">¿No tienes cuenta? Regístrate</a>
    </mat-card-actions>
  </mat-card>
</div>
